{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм — это конечная и однозначная последовательность шагов (правил), которая преобразует входные данные во выходные, решая задачу за конечное число операций с предсказуемым результатом и измеримой сложностью по времени и памяти."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определение"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм — формальное описание процедуры решения класса задач. Он задаёт, какие действия и в каком порядке нужно выполнить над входными данными, чтобы получить корректный результат. Важны не конкретный язык или технология, а логика шагов, их корректность и эффективность."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Ключевые свойства"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Входные данные: ","marks":[{"type":"bold"}]},{"type":"text","text":"указано, какие данные алгоритм принимает (могут быть и пустыми)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выход (результат): ","marks":[{"type":"bold"}]},{"type":"text","text":"чётко определено, что алгоритм возвращает и в каком формате."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Конечность: ","marks":[{"type":"bold"}]},{"type":"text","text":"выполнение завершается за конечное число шагов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Детерминированность (однозначность): ","marks":[{"type":"bold"}]},{"type":"text","text":"при одинаковых входных данных результат и последовательность действий предсказуемы (или задана вероятностная модель, если алгоритм рандомизированный)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дискретность: ","marks":[{"type":"bold"}]},{"type":"text","text":"алгоритм состоит из отдельных, выполнимых элементарных шагов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Массовость (универсальность): ","marks":[{"type":"bold"}]},{"type":"text","text":"решает не один конкретный пример, а целый класс задач (все входы, удовлетворяющие условиям)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Корректность (результативность): ","marks":[{"type":"bold"}]},{"type":"text","text":"для допустимых входов выдаёт правильный результат, соответствующий спецификации."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Эффективность и сложность: ","marks":[{"type":"bold"}]},{"type":"text","text":"оценка затрат по времени и памяти. Часто используют Big-O: "},{"type":"text","text":"O(1)","marks":[{"type":"code"}]},{"type":"text","text":", "},{"type":"text","text":"O(log n)","marks":[{"type":"code"}]},{"type":"text","text":", "},{"type":"text","text":"O(n)","marks":[{"type":"code"}]},{"type":"text","text":", "},{"type":"text","text":"O(n log n)","marks":[{"type":"code"}]},{"type":"text","text":", "},{"type":"text","text":"O(n²)","marks":[{"type":"code"}]},{"type":"text","text":" и т.д.; отдельно оценивают память."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры алгоритмов"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Линейный поиск: ","marks":[{"type":"bold"}]},{"type":"text","text":"последовательно проверяет элементы. Время — "},{"type":"text","text":"O(n)","marks":[{"type":"code"}]},{"type":"text","text":", память — "},{"type":"text","text":"O(1)","marks":[{"type":"code"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск: ","marks":[{"type":"bold"}]},{"type":"text","text":"ищет в отсортированном массиве, деля диапазон пополам. Время — "},{"type":"text","text":"O(log n)","marks":[{"type":"code"}]},{"type":"text","text":", память — "},{"type":"text","text":"O(1)","marks":[{"type":"code"}]},{"type":"text","text":". Требует предварительной сортировки."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сортировки: ","marks":[{"type":"bold"}]},{"type":"text","text":"быстрая сортировка — "},{"type":"text","text":"O(n log n)","marks":[{"type":"code"}]},{"type":"text","text":" в среднем, "},{"type":"text","text":"O(n²)","marks":[{"type":"code"}]},{"type":"text","text":" в худшем; сортировка вставками — "},{"type":"text","text":"O(n²)","marks":[{"type":"code"}]},{"type":"text","text":", но хороша на почти отсортированных данных."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Хеширование: ","marks":[{"type":"bold"}]},{"type":"text","text":"поиск/вставка в хеш-таблицу — "},{"type":"text","text":"O(1)","marks":[{"type":"code"}]},{"type":"text","text":" в среднем, "},{"type":"text","text":"O(n)","marks":[{"type":"code"}]},{"type":"text","text":" в худшем."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример кода"}]},{"type":"codeBlock","content":[{"type":"text","text":"// Линейный поиск — O(n) по времени, O(1) по памяти
function linearSearch(arr, x) {
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] === x) return i;
  }
  return -1;
}

// Бинарный поиск — O(log n) по времени, O(1) по памяти (массив должен быть отсортирован)
function binarySearch(sorted, x) {
  let l = 0, r = sorted.length - 1;
  while (l <= r) {
    const m = l + ((r - l) >> 1);
    if (sorted[m] === x) return m;
    if (sorted[m] < x) l = m + 1;
    else r = m - 1;
  }
  return -1;
}

// Быстрая сортировка (quicksort) — среднее O(n log n), худшее O(n^2)
function quickSort(a) {
  if (a.length <= 1) return a;
  const pivot = a[a.length >> 1];
  const left = [], mid = [], right = [];
  for (const v of a) {
    if (v < pivot) left.push(v);
    else if (v > pivot) right.push(v);
    else mid.push(v);
  }
  return [...quickSort(left), ...mid, ...quickSort(right)];
}

// Пример использования
const data = [5, 1, 9, 2, 7, 3];
const sorted = quickSort(data);           // [1,2,3,5,7,9]
const idx1 = linearSearch(sorted, 7);     // 4
const idx2 = binarySearch(sorted, 7);     // 4 (быстрее на больших n)"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Алгоритмы в веб‑разработке"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск и фильтрация в интерфейсах: ","marks":[{"type":"bold"}]},{"type":"text","text":"дебаунс/троттлинг обработчиков ввода, эффективные фильтры "},{"type":"text","text":"O(n)","marks":[{"type":"code"}]},{"type":"text","text":" или индексация."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Рендеринг и диффинг: ","marks":[{"type":"bold"}]},{"type":"text","text":"алгоритмы сравнения дерева (виртуальный DOM), минимизация перерисовок."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Маршрутизация и кэширование: ","marks":[{"type":"bold"}]},{"type":"text","text":"поиск маршрутов, LRU‑кэши для данных и ассетов (service worker)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обработка событий и очередей: ","marks":[{"type":"bold"}]},{"type":"text","text":"батчинг, тайм‑слайсинг, планирование задач в event loop."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Безопасность и хеши: ","marks":[{"type":"bold"}]},{"type":"text","text":"хеш‑функции, сравнение подписи, проверка целостности."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как отвечать на собеседовании"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дайте чёткое определение: что такое алгоритм и его цель."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Перечислите ключевые свойства (вход/выход, конечность, детерминированность, корректность, сложность)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Упомяните оценку сложности: ","marks":[{"type":"bold"}]},{"type":"text","text":"время и память, Big‑O."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Приведите 1–2 примера (линейный/бинарный поиск, сортировка) и короткий код."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Свяжите с практикой веб‑разработки: как вы применяли это в проекте."}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Пример краткого ответа: ","marks":[{"type":"bold"}]},{"type":"text","text":"Алгоритм — это конечная последовательность однозначных шагов для решения задачи. Важны вход и выход, корректность и эффективность. Например, бинарный поиск на отсортированном массиве работает за "},{"type":"text","text":"O(log n)","marks":[{"type":"code"}]},{"type":"text","text":" по времени и "},{"type":"text","text":"O(1)","marks":[{"type":"code"}]},{"type":"text","text":" по памяти; я применял его для ускорения поиска по предрассортированному списку."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типичные ловушки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Путать «алгоритм» и «реализацию на языке»: ","marks":[{"type":"bold"}]},{"type":"text","text":"определение должно быть технологически нейтральным."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не упомянуть вход/выход или конечность: ","marks":[{"type":"bold"}]},{"type":"text","text":"эти критерии обязательны."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Игнорировать сложность: ","marks":[{"type":"bold"}]},{"type":"text","text":"всегда говорите про время и память в терминах Big‑O."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ошибки в предпосылках: ","marks":[{"type":"bold"}]},{"type":"text","text":"например, бинарный поиск работает только на отсортированных данных."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Конечность: алгоритм обязан завершаться за конечное число шагов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определенность (однозначность): каждая инструкция сформулирована однозначно; на каждом шаге нет двусмысленности."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дискретность: процесс состоит из отдельных, четко отделенных шагов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Массовость (общность): алгоритм применим к целому классу входных данных, а не к единственному примеру."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Результативность и корректность: для допустимых входов получается результат, удовлетворяющий спецификации."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Эффективность: разумные затраты времени и памяти; оценимая вычислительная сложность."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Ниже — ключевые свойства алгоритма, зачем они нужны на практике и как распознать их на примерах."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1) Конечность (остановка)"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм должен гарантированно завершаться за конечное число шагов при любых допустимых входных данных. В противном случае это бесконечный процесс, а не алгоритм."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверка: есть ли инвариант и убывающая мера, которая строго сокращается на каждом цикле и достигает базового случая?"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Признак проблемы: цикл/рекурсия без условие выхода, которое гарантированно станет истинным."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Пример нарушения конечности:
function loopForever() {
  while (true) {
    // нет убывающей меры и условия выхода
  }
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2) Определенность (однозначность инструкций)"}]},{"type":"paragraph","content":[{"type":"text","text":"Каждый шаг должен быть описан однозначно: исполнителю (компьютеру) не должно требоваться интерпретировать смысл. Это исключает неоднозначные термины вроде «обработать», «упростить», «значительно уменьшить» без строгого определения."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Плохо (неопределенность):
// "Выполнить обработку ввода"
// Не ясно: что именно и как?

// Хорошо (определенно):
function normalize(input) {
  // 1) trim пробелы по краям
  // 2) перевести в нижний регистр
  // 3) заменить последовательности пробелов одним пробелом
  return input.trim().toLowerCase().replace(/\s+/g, ' ');
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"3) Дискретность"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм должен состоять из последовательности элементарных шагов, каждый из которых исполним и имеет наблюдаемый эффект. Это позволяет анализировать корректность и сложность по шагам."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Дискретные шаги сортировки выбором (описаны явно):
function selectionSort(a) {
  const n = a.length;
  for (let i = 0; i < n - 1; i++) {             // шаг: выбор позиции i
    let min = i;                                 // шаг: предполагаем минимум
    for (let j = i + 1; j < n; j++) {            // шаг: поиск минимума в хвосте
      if (a[j] < a[min]) min = j;                // шаг: обновление минимума
    }
    if (min !== i) [a[i], a[min]] = [a[min], a[i]]; // шаг: обмен
  }
  return a;
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"4) Массовость (общность)"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм должен быть применим к целому семейству входов, описанных доменом. В спецификации фиксируются требования к входу (предусловия) и форма результата (постусловие)."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Бинарный поиск работает для любого отсортированного массива сравнимых элементов
// (предусловие: массив отсортирован по неубыванию)
function binarySearch(arr, x) {
  let l = 0, r = arr.length - 1;
  while (l <= r) {
    const m = l + ((r - l) >> 1);
    if (arr[m] === x) return m;      // постусловие: индекс найденного элемента
    if (arr[m] < x) l = m + 1; else r = m - 1;
  }
  return -1;                         // если элемента нет
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"5) Результативность и корректность"}]},{"type":"paragraph","content":[{"type":"text","text":"Результативность: алгоритм всегда выдает некоторый результат для допустимых входов. Корректность: этот результат удовлетворяет спецификации (постусловиям). Доказуемость корректности — важнейшее требование к алгоритмам, используемым в продакшене."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Спецификация (словами):
// Вход: неотрицательные целые a, b, не оба нули.
// Выход: gcd(a, b) — наибольший общий делитель, т.е. d | a, d | b и
// для любого d' | a и d' | b верно d' <= d.

function gcd(a, b) {
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return Math.abs(a);
}

// Корректность эскизно:
// - Инвариант: gcd(a, b) не меняется при замене (a, b) := (b, a mod b).
// - Терминация: b уменьшается по модулю и достигает 0 за конечное число шагов.
// - Постусловие: когда b = 0, ответ a — искомый НОД."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"6) Эффективность (сложность по времени и памяти)"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм должен решать задачу с приемлемыми затратами. Эффективность выражают асимптотически (O-нотация) и эмпирически (бенчмарки). На интервью важно уметь обсудить временную и пространственную сложность, а также возможные оптимизации."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: сколько элементарных операций выполняется (например, O(n log n))."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: дополнительный объём памяти (например, O(1) у Евклида)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Компромиссы: время ↔ память, точность ↔ скорость и т. п."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Наивный НОД (неэффективный): O(min(a,b))
function gcdNaive(a, b) {
  let d = Math.min(a, b);
  while (d > 0) {
    if (a % d === 0 && b % d === 0) return d;
    d--;
  }
}

// Евклид эффективнее: O(log min(a,b)) шагов."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Связанные понятия, которые часто спрашивают"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Входы/выходы: чёткое определение формата данных и контрактов (пред- и постусловия)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Детерминированность vs недетерминированность: алгоритм может быть недетерминированным, но его спецификация и корректность должны быть определены (например, любой допустимый результат из множества)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Доказываемость: инварианты циклов, рекурсивные базовые случаи, убывающая мера, частичная/тотальная корректность."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Итоговая выжимка (для ответа на собеседовании)"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм — это конечная, дискретная и однозначная последовательность шагов, применимая к целому классу входов (массовость), которая для допустимых данных гарантирует получение корректного результата и делает это эффективно по времени и памяти."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Дискретность алгоритма — это свойство решать задачу через последовательность отдельных, неделимых шагов (итераций), где каждое состояние и действие описываются конечным набором символов, а изменения происходят скачкообразно, шаг-за-шагом, а не непрерывно."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"В информатике алгоритм по определению дискретен: он выполняется шагами, меняя состояние системы в отдельные, различимые моменты времени. Это позволяет формально описывать, анализировать и реализовывать алгоритмы на цифровых машинах."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Ключевые аспекты дискретности"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Шаговость выполнения: алгоритм исполняется как последовательность атомарных "},{"type":"text","text":"шагов","marks":[{"type":"code"}]},{"type":"text","text":", каждый из которых переводит систему из состояния "},{"type":"text","text":"S","marks":[{"type":"code"}]},{"type":"text","text":" в "},{"type":"text","text":"S′","marks":[{"type":"code"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Атомарность операций: базовые действия считаются неделимыми и выполняются целиком (сравнение двух значений, присваивание, доступ к элементу массива и т.п.)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дискретные представления: входные данные, внутренние состояния и выход кодируются конечными строками символов (битами, числами с конечной разрядностью и т.д.)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дискретное «время»: между шагами нет бесконечного числа промежуточных состояний; индекс шага — целое число "},{"type":"text","text":"k = 0, 1, 2, …","marks":[{"type":"code"}]},{"type":"text","text":"."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Почему это важно"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Реализуемость: цифровые компьютеры сами по себе дискретны, поэтому алгоритмы, построенные из конечного набора шагов и символов, могут быть реализованы и исполнены."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Формальная проверяемость: наличие отдельных шагов и состояний позволяет доказывать корректность (инварианты, частичная/полная корректность), анализировать сложность и ресурсы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Тестируемость и воспроизводимость: дискретные шаги упрощают воспроизведение сценариев, отладку и измерения."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Связь с непрерывными задачами"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритмы часто решают задачи из непрерывных областей (например, оптимизация на вещественных числах, интегрирование дифференциальных уравнений). При этом сами алгоритмы остаются дискретными: они берут конечные измерения, делают конечное число шагов и выдают конечный по точности результат. Переход от непрерывной постановки к дискретной процедуре называется дискретизацией."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Чем дискретность не является"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не про детерминизм: алгоритм может быть дискретным и при этом вероятностным или недетерминированным — важна шаговость, а не предсказуемость результата."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не гарантия завершения: дискретность не означает, что алгоритм обязательно завершится; свойство завершения рассматривается отдельно."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не требует дискретной предметной области: даже на вещественных числах алгоритм работает с конечной точностью (плавающая запятая), выполняя дискретные шаги."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Интуитивно-формальное описание"}]},{"type":"paragraph","content":[{"type":"text","text":"Пусть "},{"type":"text","text":"S₀","marks":[{"type":"code"}]},{"type":"text","text":" — начальное состояние, "},{"type":"text","text":"S₁, S₂, …","marks":[{"type":"code"}]},{"type":"text","text":" — состояния после применения правил. Алгоритм — это отношение перехода "},{"type":"text","text":"→","marks":[{"type":"code"}]},{"type":"text","text":" такое, что на каждом шаге выполняется один (или конечное число) атомарных переходов "},{"type":"text","text":"Sₖ → Sₖ₊₁","marks":[{"type":"code"}]},{"type":"text","text":". Шаги индексируются целыми "},{"type":"text","text":"k","marks":[{"type":"code"}]},{"type":"text","text":" — это и есть дискретность."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример 1: двоичный поиск (строго дискретный)"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм делает последовательность сравнения/деления пополам; каждое сравнение — атомарный шаг."}]},{"type":"codeBlock","content":[{"type":"text","text":"function binarySearch(arr, x) {
  let l = 0, r = arr.length - 1;
  while (l <= r) {
    const m = (l + r) >> 1; // дискретный выбор середины
    if (arr[m] === x) return m;           // атомарная проверка
    if (arr[m] < x) l = m + 1; else r = m - 1; // дискретный переход состояния
  }
  return -1; // не найдено
}"}]},{"type":"paragraph","content":[{"type":"text","text":"Каждая итерация — один дискретный шаг; число шагов пропорционально "},{"type":"text","text":"O(log n)","marks":[{"type":"code"}]},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример 2: дискретизация непрерывной задачи (метод Эйлера)"}]},{"type":"paragraph","content":[{"type":"text","text":"Решаем дифференциальное уравнение "},{"type":"text","text":"y′ = f(t, y)","marks":[{"type":"code"}]},{"type":"text","text":" с шагом "},{"type":"text","text":"h","marks":[{"type":"code"}]},{"type":"text","text":". Хотя сама задача непрерывна, процедура — дискретная: мы изменяем "},{"type":"text","text":"t","marks":[{"type":"code"}]},{"type":"text","text":" скачками "},{"type":"text","text":"h","marks":[{"type":"code"}]},{"type":"text","text":" и делаем конечные вычисления на каждом шаге."}]},{"type":"codeBlock","content":[{"type":"text","text":"function euler(f, y0, t0, t1, h) {
  const points = [[t0, y0]];
  for (let t = t0; t < t1; t += h) {
    y0 = y0 + h * f(t, y0); // дискретное обновление состояния
    points.push([t + h, y0]);
  }
  return points;
}

// Пример: y' = y, y(0) = 1, ожидаем exp(t)
const approx = euler((t, y) => y, 1, 0, 1, 0.1);
console.log(approx);"}]},{"type":"paragraph","content":[{"type":"text","text":"Уменьшая "},{"type":"text","text":"h","marks":[{"type":"code"}]},{"type":"text","text":", повышаем точность, но алгоритм остаётся дискретным: он совершает конечные, атомарные шаги."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Контрпример (не дискретно)"}]},{"type":"paragraph","content":[{"type":"text","text":"«Повернуть ручку ровно на π/10 оборота с бесконечной точностью» — это требование к непрерывному физическому процессу с бесконечной точностью измерения. Такой процесс нельзя представить конечной последовательностью атомарных шагов с конечной точностью кодирования состояния, поэтому это не алгоритм в строгом дискретном смысле."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Дискретность — базовое свойство алгоритмов, позволяющее их формально описывать, анализировать и реализовывать: алгоритмы работают с конечными описаниями состояний и выполняют решение задач шаг-за-шагом. Даже для непрерывных задач мы используем дискретные процедуры (дискретизацию) и выдаём ответы конечной точности."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Входные данные алгоритма — это значения/структуры, которые алгоритм принимает на вход и над которыми выполняет операции. Выходные данные — это результат работы алгоритма, возвращаемый после обработки входа. Формально алгоритм реализует отображение f: X → Y, где X — множество допустимых входов (домен), а Y — множество возможных выходов (кодомен), иногда с учётом ошибок: f: X → Y ∪ E."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный разбор"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определения"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Входные данные (input):"},{"type":"text","text":" значения, параметры, структуры или потоки, которые подаются алгоритму для обработки."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выходные данные (output):"},{"type":"text","text":" результат вычислений — значение, структура, поток или сигнал (включая ошибку), которые алгоритм возвращает наружу."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Ключевые свойства и требования"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Домен и валидность: какие значения считаются допустимыми входами (типы, диапазоны, формат). Алгоритм должен уметь валидировать вход и корректно обрабатывать недопустимые случаи."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Детерминированность: для детерминированных алгоритмов одинаковый вход ⇒ одинаковый выход. Для недетерминированных выход может зависеть от случайности/окружения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Явность форматов: чёткие контракты входа/выхода (типы, единицы измерения, кодировки, локаль, сортировка, пагинация и т. п.)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ошибки как часть выхода: ошибки — это тоже форма выхода (исключение, код статуса, Result<T, E>), даже если они сигнализируют о невозможности получить основной результат."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Отделение побочных эффектов: логирование, запись в БД, отправка писем — это не «выходные данные», а побочные эффекты. Выход — то, что возвращается как результат вычисления."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типы входов/выходов (на практике)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Скалярные: числа, строки, булевы значения, даты/таймстемпы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Структурированные: объекты/словари, записи, JSON."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Коллекции: массивы, списки, множества, карты."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Потоки: байтовые потоки, итераторы, реактивные потоки (Observable)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сигналы состояния: коды статуса, флаги успеха/ошибки, исключения, Result<E, T>."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры из разработки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сортировка массива: вход — массив чисел/строк, выход — отсортированный массив (той же длины)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Логин: вход — email/логин и пароль; выход — токен/сессия или ошибка авторизации."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"REST-эндпоинт GET /users?limit=10&offset=20: вход — query-параметры; выход — JSON-список пользователей и метаданные пагинации или ошибка 4xx/5xx."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Хеш-функция: вход — байтовая строка; выход — фиксированная хеш-строка."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Формализация"}]},{"type":"paragraph","content":[{"type":"text","text":"Алгоритм можно рассматривать как функцию f: X → Y, где X — множество допустимых входов, Y — множество выходов. На практике часто полезно явным образом учитывать ошибки: f: X → Y ∪ E, или использовать типы вроде Result<Y, E>. Если часть входов не поддерживается, то f является частичной: определена не на всём X, и это должно быть отражено в контракте."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Границы и крайние случаи"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Пустые входы: пустой массив, пустая строка — что возвращать? Часто — нейтральный элемент или ошибка в зависимости от задачи."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Невалидные значения: null/undefined/NaN, неверный формат, неправильная кодировка."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Переполнения/подтекающие типы: большие числа, длинные строки, большие файлы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Недетерминизм: зависимость от времени, случайности, сети — фиксируйте это в контракте (семена RNG, таймауты, ретраи)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример кода (JavaScript)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// Алгоритм: посчитать среднее по массиву чисел с валидацией входа.
// Вход: numbers: unknown
// Выход: объект-результат { ok: boolean, value?: number, error?: string, meta?: object }

function safeAverage(numbers) {
  if (!Array.isArray(numbers)) {
    return { ok: false, error: 'numbers must be an array' }; // ошибка как выход
  }
  const filtered = numbers.filter(n => typeof n === 'number' && Number.isFinite(n));
  if (filtered.length === 0) {
    return { ok: false, error: 'no valid numbers' };
  }
  const sum = filtered.reduce((a, b) => a + b, 0);
  const avg = sum / filtered.length;
  return { ok: true, value: avg, meta: { count: filtered.length } }; // основной выход
}

// Примеры использования:
// Вход: [1, 2, 3]
// Выход:
// { ok: true, value: 2, meta: { count: 3 } }

// Вход: ['a', Infinity]
// Выход:
// { ok: false, error: 'no valid numbers' }

// Дополнительно: парсинг query-строки (ещё один алгоритм)
function parseQuery(qs) {
  const params = new URLSearchParams(qs.startsWith('?') ? qs.slice(1) : qs);
  const result = {};
  for (const [k, v] of params) {
    if (k in result) result[k] = Array.isArray(result[k]) ? result[k].concat(v) : [result[k], v];
    else result[k] = v;
  }
  return result;
}
// Вход: '?q=test&tags=js&tags=algo'
