START
  READ nums (length > 0)
  max := nums[0]
  FOR i := 1 TO length(nums)-1 DO
    IF nums[i] > max THEN
      max := nums[i]
    ENDIF
  ENDFOR
  PRINT max
END"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function maxInArray(nums) {
  if (!Array.isArray(nums) || nums.length === 0) {
    throw new Error('Массив пуст или некорректен');
  }
  let max = nums[0];
  for (let i = 1; i < nums.length; i++) {
    if (nums[i] > max) max = nums[i];
  }
  return max;
}

