console.log(firstNegative); // -2
"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"JS (неблокирующий): ожидание условия с таймаутом"}]},{"type":"paragraph","content":[{"type":"text","text":"В браузерном/Node.js коде нельзя крутить "пустой" while для ожидания — он блокирует поток. Вместо этого используйте await внутри цикла:"}]},{"type":"codeBlock","content":[{"type":"text","text":"async function waitFor(predicate, timeoutMs = 2000, intervalMs = 50) {
  const end = Date.now() + timeoutMs;
  while (!predicate()) { // предусловие проверяется перед каждой итерацией
    if (Date.now() > end) throw new Error('Timeout');
    await new Promise(r => setTimeout(r, intervalMs));
  }
}

