  console.log('Выполнится один раз');
} while (m > 0);
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типичные ошибки и как избежать"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бесконечный цикл: забыли изменить переменные, влияющие на условие."}]},{"type":"paragraph","content":[{"type":"text","text":"Решение: обновляйте счётчики/состояние внутри тела цикла или используйте for, если уместно."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнение чисел с плавающей точкой на равенство."}]},{"type":"paragraph","content":[{"type":"text","text":"Решение: проверяйте через диапазон (|a−b| < eps) или используйте сравнения >/<."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Мутация коллекции при обходе (изменение длины массива во время итерации)."}]},{"type":"paragraph","content":[{"type":"text","text":"Решение: итерируйтесь по копии или контролируйте индекс и границы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Блокировка UI/сервера в JS долгим синхронным while."}]},{"type":"paragraph","content":[{"type":"text","text":"Решение: разбивайте работу на чанки (setTimeout/queueMicrotask) или используйте await внутри цикла."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Слишком сложное условие, трудно поддерживать."}]},{"type":"paragraph","content":[{"type":"text","text":"Решение: вынесите проверку в функцию с говорящим названием (isReady(), hasMore())."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Инвариант и завершение (для собеседований)"}]},{"type":"paragraph","content":[{"type":"text","text":"Инвариант — свойство, истинное до и после каждой итерации. Для корректности цикла сформулируйте:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Инвариант: что не меняется (например, «все обработанные элементы удовлетворяют условию»)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Мера прогресса: что монотонно приближает к завершению (индекс растёт, очередь убывает, время истекает)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Условие выхода: когда и почему оно станет ложным."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда использовать"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Количество повторений заранее неизвестно и зависит от данных/событий."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нужно проверять условие до выполнения шага (например, есть ли ещё данные)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Чтение из потока/очереди до опустошения, поиск до нахождения результата, ожидание состояния."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Цикл с предусловием (например, while) проверяет условие до входа в тело, поэтому тело выполняется только если условие истинно. Это удобный инструмент для задач с неизвестным заранее числом итераций; важно обеспечить изменение состояния, ведущее к ложности условия, чтобы избежать бесконечных циклов."}]}]}

