    {
      "type": "codeBlock",
      "attrs": { "language": "javascript" },
      "content": [
        {
          "type": "text",
          "text": "function grade(score) {\n  if (score < 0 || score > 100) return \"invalid\"; // гвард-кейс\n  if (score >= 90) return \"A\";\n  if (score >= 75) return \"B\";\n  if (score >= 60) return \"C\";\n  if (score >= 40) return \"D\";\n  return \"F\";\n}\n\nconsole.log([95, 76, 12, 101].map(grade));"
        }
      ]
    },
    {
      "type": "orderedList",
      "attrs": { "start": 1 },
      "content": [
        {
          "type": "listItem",
          "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Следите за полнотой условий (обработайте крайние случаи)." }] }]
        },
        {
          "type": "listItem",
          "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Располагаете проверки от более строгих к менее строгим (или наоборот, но последовательно)." }] }]
        },
        {
          "type": "listItem",
          "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Избегайте “лесенок” if-else, если можно заменить на таблицу соответствий/мапу." }] }]
        }
