},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Алгоритмическую сложность и объём данных (Big-O, память, масштабируемость)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Объём работ: фичи, интеграции, миграции, тестирование, документация, релиз."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Неопределённость и риски: неизвестные требования, протоколы, доступы, нестабильные API."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Зависимости: другие команды, библиотеки, инфраструктура, окна на релиз/безопасность."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нефункциональные требования: производительность, доступность, SLA, наблюдаемость."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Качество и безопасность: код-ревью, тест-пирамида, секреты, соответствие политике."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как оценивать на практике"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Разбейте на атомарные задачи с критериями приёмки (Definition of Done)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выберите шкалу: story points, T-shirt sizes, человеко-дни/часы (для контрактов)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Учтите риски и добавьте буфер (на исследования, ожидание доступов/ревью/релиза)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сверьтесь с историческими данными и velocity команды."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Валидируйте оценку с командой (планнинг-покер, асинхронный опрос, экспертная калибровка)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Пересматривайте оценку по мере появления новой информации (rolling-wave planning)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Частые ошибки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Путать оценку и обещание: оценка — это прогноз с вероятностью, а не гарантированный дедлайн."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не учитывать полный цикл: анализ, UX, тесты, ревью, фиксы, релиз, откатный план."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Игнорировать зависимости и внешние очереди (DevOps, безопасность, смежные команды)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Переусложнять решение или делать преждевременную оптимизацию."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Отсутствие критериев готовности — сложно оценить то, что плохо сформулировано."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оптимистическое смещение и якорение без опоры на исторические данные/факты."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не обновлять оценку при изменении скоупа или требований."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример: влияние алгоритмической сложности на сроки"}]},{"type":"paragraph","content":[{"type":"text","text":"Одна и та же бизнес-задача может иметь разные варианты реализации с различной сложностью. Например, поиск двух чисел с заданной суммой:"}]},{"type":"codeBlock","content":[{"type":"text","text":"// Вариант 1: наивный O(n^2)
function twoSumBruteForce(nums, target) {
  for (let i = 0; i < nums.length; i++) {
    for (let j = i + 1; j < nums.length; j++) {
      if (nums[i] + nums[j] === target) return [i, j];
    }
  }
  return null;
}

// Вариант 2: через хеш-таблицу O(n), доп. память O(n)
function twoSumHash(nums, target) {
  const map = new Map();
  for (let i = 0; i < nums.length; i++) {
    const need = target - nums[i];
    if (map.has(need)) return [map.get(need), i];
    map.set(nums[i], i);
  }
  return null;
