        {
          "type": "text",
          "text": "// O(1): доступ по индексу и push (амортизированно)\nconst arr = [10, 20, 30];\nconst x = arr[1]; // O(1)\narr.push(40);      // амортизированно O(1)\n\n// O(n): линейный поиск\nfunction linearSearch(a, target) {\n  for (let i = 0; i < a.length; i++) {\n    if (a[i] === target) return i; // лучший случай: O(1), худший: O(n)\n  }\n  return -1;\n}\n\n// O(log n): бинарный поиск (массив должен быть отсортирован)\nfunction binarySearch(a, target) {\n  let l = 0, r = a.length - 1;\n  while (l <= r) {\n    const m = (l + r) >> 1;\n    if (a[m] === target) return m;\n    if (a[m] < target) l = m + 1; else r = m - 1;\n  }\n  return -1; // худший случай: O(log n)\n}\n\n// O(n log n): сортировка (типичная средняя оценка)\nconst sorted = [...arr].sort((a, b) => a - b); // средняя: O(n log n)\n\n// O(n^2): вложенные циклы\nfunction hasDuplicatesQuadratic(a) {\n  for (let i = 0; i < a.length; i++) {\n    for (let j = i + 1; j < a.length; j++) {\n      if (a[i] === a[j]) return true;\n    }\n  }\n  return false; // худший случай: O(n^2)\n}\n\n// Оптимизация до O(n) по времени и O(n) по памяти с использованием множества\nfunction hasDuplicatesLinear(a) {\n  const seen = new Set();\n  for (const v of a) {\n    if (seen.has(v)) return true;\n    seen.add(v);\n  }\n  return false; // время: O(n), память: O(n)\n}"
