}

console.log(sumNested([1, [2, [3, 4]], 5])); // 15"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсивный случай обрабатывает вложенный массив, пока не дойдёт до чисел (базовый случай)."}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"Бинарный поиск (разделяй и властвуй)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function binarySearch(arr, target, left = 0, right = arr.length - 1) {
  // Базовый случай: диапазон пуст
  if (left > right) return -1;
  const mid = Math.floor((left + right) / 2);
  if (arr[mid] === target) return mid; // Базовый случай: найдено
  // Рекурсивный случай: сузить поиск в одну из половин
  if (arr[mid] > target) return binarySearch(arr, target, left, mid - 1);
  return binarySearch(arr, target, mid + 1, right);
}

console.log(binarySearch([1, 2, 3, 4, 5], 4)); // 3"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсивный случай уменьшает размер диапазона вдвое на каждом шаге, гарантируя прогресс к базовому случаю."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Частые ошибки в рекурсивном случае"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нет базового случая или он недостижим — бесконечная рекурсия и переполнение стека."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нет прогресса — аргументы рекурсивного вызова не приближают к остановке (например, вы передаёте те же значения)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Экспоненциальное дублирование подзадач — классический fib(n) без мемоизации (два рекурсивных вызова, большие перекрытия). Решение: мемоизация/динамическое программирование или итерация."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Забыли вернуть результат рекурсивного вызова — функция всегда возвращает undefined/неверный результат."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Мутация общей структуры между ветками — трудно отслеживаемые баги. Лучше делать чистые функции или копии, если нужно."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как проверить корректность рекурсивного случая"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ясно сформулируйте базовый случай и покажите, что он достижим."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Докажите прогресс: на каждом шаге вход становится "меньше" (размер, глубина, расстояние, диапазон)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определите инвариант — что остаётся истинным до и после рекурсивного шага."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверьте комбинирование результатов: корректно ли вы собираете итог из подрезультатов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оцените сложность (временную и пространственную) и избегайте избыточных вызовов (используйте мемоизацию, если нужно)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Покройте граничные случаи тестами: пустые входы, минимальные/максимальные значения, глубокая вложенность."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Шаблон для собеседования"}]},{"type":"codeBlock","content":[{"type":"text","text":"function solve(problem) {
  // 1) Базовый случай(и)
  if (isBase(problem)) return baseAnswer(problem);

  // 2) Прогресс: упростить задачу
  const smaller = reduce(problem);

  // 3) Рекурсивный случай: решить подзадачу
  const partial = solve(smaller);

  // 4) Комбинация результатов
  return combine(problem, partial);
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда использовать рекурсию"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Деревья и графы: обходы (DFS), вычисления на поддеревьях, поиск путей (с учётом множества посещённых)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Разделяй и властвуй: бинарный поиск, быстрая сортировка, слияние, построение сегментных деревьев."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бэктрекинг: перебор с откатами (генерация перестановок, N-ферзей, парсинг)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Задачи с естественной рекурсивной структурой данных или формулой (например, рекурсивные определения)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Хвостовая рекурсия и итерация"}]},{"type":"paragraph","content":[{"type":"text","text":"Хвостовая рекурсия — когда рекурсивный вызов является последней операцией функции и результат возвращается напрямую. Это позволяет потенциально оптимизировать стек, но в JavaScript такая оптимизация не гарантирована. Для больших глубин предпочтительнее итерация или явный стек."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Знание основ алгоритмов помогает разработчику осознанно выбирать решения, прогнозировать производительность (время и память), находить и устранять узкие места, писать надёжный и масштабируемый код, эффективнее общаться с командой и уверенно проходить собеседования."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Понимание сложности (Big-O) — предсказуемая производительность и контроль затрат."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выбор подходящих структур данных (массивы, хеш-таблицы, деревья, очереди/стеки)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Масштабируемость — код работает быстро и стабильно при росте объёмов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск узких мест и оптимизация без преждевременного «микротюнинга»."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Лучшее проектирование API и системные компромиссы (скорость vs память vs простота)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Собеседования — умение объяснять решения и торговаться за компромиссы."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Что дают алгоритмы на практике"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Предсказуемость и контроль производительности: оценка сложности по времени и памяти (Big-O) позволяет понять, выдержит ли решение реальные нагрузки."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Осознанный выбор структур данных: хеш-таблица для быстрых поисков, очередь для задач в порядке поступления, куча для приоритетов, дерево для диапазонов/поиска по ключу и т.д."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Устойчивость и надёжность: корректные алгоритмы учитывают крайние случаи, избегают тайм-аутов и утечек памяти."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сокращение затрат: меньшая вычислительная сложность = меньше CPU/памяти/времени отклика = ниже стоимость инфраструктуры и выше SLO/SLI."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Коммуникация и ревью: проще объяснить и защитить решение, быстро читать чужой код, замечать потенциальные проблемы до продакшена."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как это проявляется в повседневной web‑разработке"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Интерфейсы с большими списками: виртуализация, батчинг обновлений и эффективные структуры данных уменьшают количество операций рендеринга и работу GC."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск и фильтрация: бинарный поиск, суффиксные/префиксные структуры, индексы и кэширование ускоряют выдачу и автодополнение."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Серверные API: пагинация, сортировка, использование индексов и алгоритмически корректные запросы предотвращают full scan и перегрузку БД."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обработка событий: debounce/throttle — прикладные паттерны с чёткими гарантиями, снижающие количество вызовов обработчиков."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Базовые темы, которые стоит знать"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Асимптотическая сложность: O(1), O(log n), O(n), O(n log n), O(n²); оценка по времени и памяти, худший/средний/лучший случаи."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Структуры данных: массивы, связные списки, стек/очередь/дек, хеш-таблица/Set/Map, дерево/БДП, куча (приоритетная очередь), графы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Алгоритмы: сортировки, поиск (линейный/бинарный), обходы графов (BFS/DFS), два указателя, скользящее окно, жадные и основы динамического программирования."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры кода"}]},{"type":"paragraph","content":[{"type":"text","text":"Ниже — типичные иллюстрации того, как выбор алгоритма радикально влияет на эффективность."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1) Поиск двух чисел с заданной суммой"}]},{"type":"paragraph","content":[{"type":"text","text":"Наивный O(n²): перебор всех пар."}]},{"type":"codeBlock","content":[{"type":"text","text":"function twoSumQuadratic(nums, target) {
  for (let i = 0; i < nums.length; i++) {
    for (let j = i + 1; j < nums.length; j++) {
      if (nums[i] + nums[j] === target) return [i, j];
    }
  }
  return null;
}"}]},{"type":"paragraph","content":[{"type":"text","text":"Оптимальный O(n): используем хеш-таблицу (Map) для хранения уже виденных чисел."}]},{"type":"codeBlock","content":[{"type":"text","text":"function twoSumLinear(nums, target) {
  const seen = new Map(); // value -> index
  for (let i = 0; i < nums.length; i++) {
    const need = target - nums[i];
    if (seen.has(need)) return [seen.get(need), i];
    seen.set(nums[i], i);
  }
  return null;
}"}]},{"type":"paragraph","content":[{"type":"text","text":"Обмен: ускоряем время с O(n²) до O(n), расходуя O(n) памяти. Для больших входов это критично."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2) Бинарный поиск по отсортированному массиву — O(log n)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function binarySearch(arr, x) {
  let l = 0, r = arr.length - 1;
  while (l <= r) {
    const m = l + ((r - l) >> 1);
    if (arr[m] === x) return m;
    if (arr[m] < x) l = m + 1; else r = m - 1;
  }
  return -1;
}

// Пример:
// binarySearch([1, 3, 5, 7, 9], 7) -> 3"}]},{"type":"paragraph","content":[{"type":"text","text":"Используется в автодополнении, поиске по индексам, бинарных протоколах, пагинации по ключам."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"3) Дедупликация и подсчёт частоты с Map — O(n) + сортировка O(k log k)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function countFrequencies(items) {
  const freq = new Map();
  for (const it of items) {
    freq.set(it, (freq.get(it) || 0) + 1);
  }
  // Массив пар [значение, частота], отсортируем по убыванию частот
  return Array.from(freq.entries())
    .sort((a, b) => b[1] - a[1] || String(a[0]).localeCompare(String(b[0])));
}

